import type { Metadata } from "next";
import AircraftMaintenance from "./AircraftMaintenance";

export const metadata: Metadata = {
  title: "機体整備管理コンソール — 群青エアラインズ 整備本部 | ぐんじょう 航空",
  description:
    "航空機の機体整備管理（MRO）コンソール。整備管理者向けに、保有機材（機番(レジ)・型式・FH/FC・状態）を一覧し、整備周期（飛行時間FH／サイクルFC／経過日数 vs 限度）を機体ごとに消費量で判定して限度接近・超過をトリアージ。整備計画（格納庫ドックへの入出庫）をドック×時間軸のガントと占有マトリクスで把握し、要対応キュー（AD/SB期限・MEL是正・限度超過接近・部品寿命LLP）を重大度順に整理。A整備／C整備／重整備(D)／ライン整備の体系に沿った整備記録を確認主任者がサインオフして確定・ロックし、機体詳細で整備履歴・次回予定・保留MELをドリルインできる。",
};

export default function AircraftMaintenancePage() {
  return <AircraftMaintenance />;
}

"use client"

import * as React from "react"
import type { ColumnDef } from "@gunjo/ui"
import {
  ActionDataTable,
  ActionQueue,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Gantt,
  type GanttItem,
  type GanttItemTone,
  InspectorPanel,
  InspectorSection,
  InspectorField,
  MetadataList,
  Meter,
  type MeterTone,
  PageHeader,
  ScheduleGrid,
  type ScheduleCell,
  SignedRecord,
  type SignedRecordValue,
  StatGroup,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
} from "@gunjo/ui"

import {
  ACTIONS,
  type Aircraft,
  DOCKS,
  DOCK_PLANS,
  FLEET,
  type FleetStatus,
  PLAN_RANGE,
  RECORD,
  STATUS_LABEL,
  TODAY,
} from "./data"

// --- helpers ---------------------------------------------------------------

const STATUS_VARIANT: Record<FleetStatus, "success" | "info" | "warning"> = {
  "in-service": "success",
  "in-hangar": "info",
  attention: "warning",
}

const nf = new Intl.NumberFormat("ja-JP")

/** consumed-vs-limit → Meter. capacity semantics: near-full warns, over is bad. */
function dueTone(consumed: number, limit: number): MeterTone {
  const ratio = consumed / limit
  if (ratio >= 1) return "destructive"
  if (ratio >= 0.95) return "destructive"
  if (ratio >= 0.85) return "warning"
  return "success"
}

const GANTT_TONE: Record<string, GanttItemTone> = {
  "in-work": "info",
  confirmed: "primary",
  planned: "muted",
}

// --- fleet table -----------------------------------------------------------

function FleetTable({
  onSelect,
  selectedReg,
}: {
  onSelect: (a: Aircraft) => void
  selectedReg: string
}) {
  const columns = React.useMemo<ColumnDef<Aircraft>[]>(
    () => [
      {
        accessorKey: "reg",
        header: "機番(レジ)",
        cell: ({ row }) => (
          <span className="font-mono font-semibold tabular-nums">
            {row.original.reg}
          </span>
        ),
      },
      { accessorKey: "type", header: "型式" },
      { accessorKey: "base", header: "基地" },
      {
        accessorKey: "fh",
        header: "FH / FC",
        cell: ({ row }) => (
          <span className="tabular-nums text-muted-foreground">
            {nf.format(row.original.fh)} FH ／ {nf.format(row.original.fc)} FC
          </span>
        ),
      },
      {
        id: "next",
        header: "次回整備",
        cell: ({ row }) => {
          const a = row.original
          return (
            <span className="whitespace-nowrap">
              <span className="font-medium">{a.nextCheck}</span>{" "}
              <span className="text-muted-foreground tabular-nums">
                〜{a.due.dueDate}
              </span>
            </span>
          )
        },
      },
      {
        id: "due",
        header: "整備周期 残り",
        size: 220,
        cell: ({ row }) => {
          const { consumed, limit, basis } = row.original.due
          const remaining = Math.max(limit - consumed, 0)
          return (
            <Meter
              size="inline"
              value={consumed}
              max={limit}
              tone={dueTone(consumed, limit)}
              label={`${row.original.reg} ${row.original.nextCheck} 消費 ${consumed}/${limit}${basis}`}
              formatValue={() => `残 ${nf.format(remaining)}${basis}`}
            />
          )
        },
      },
      {
        accessorKey: "status",
        header: "状態",
        cell: ({ row }) => (
          <Badge variant={STATUS_VARIANT[row.original.status]}>
            {STATUS_LABEL[row.original.status]}
          </Badge>
        ),
      },
    ],
    []
  )

  return (
    <ActionDataTable<Aircraft, unknown>
      columns={columns}
      data={FLEET}
      getRowId={(r) => r.reg}
      getRowLabel={(r) => `${r.reg} ${r.type}`}
      filter={{ columnId: "reg", placeholder: "機番で絞り込み…" }}
      pageSize={10}
      onRowClick={onSelect}
      getRowState={(r) => (r.reg === selectedReg ? "selected" : undefined)}
      rowActions={[
        {
          id: "detail",
          label: "詳細を開く",
          onSelect: (r) => onSelect(r),
        },
      ]}
      labels={{ filterPlaceholder: "機番で絞り込み…", noResults: "該当機なし" }}
    />
  )
}

// --- dock plan (Gantt) -----------------------------------------------------

function DockPlanGantt() {
  const rows = DOCKS.map((d) => ({ id: d.id, label: d.label, sublabel: d.sub }))
  const items: GanttItem[] = DOCK_PLANS.map((p) => ({
    id: p.id,
    rowId: p.dockId,
    start: p.in,
    end: p.out,
    label: `${p.reg}・${p.check}`,
    tone: GANTT_TONE[p.status],
    ariaLabel: `${p.reg} ${p.check} ${p.in}入庫 ${p.out}出庫 ${
      p.status === "in-work" ? "作業中" : p.status === "confirmed" ? "確定" : "計画"
    }`,
  }))

  return (
    <Gantt
      rows={rows}
      items={items}
      startDate={PLAN_RANGE.start}
      endDate={PLAN_RANGE.end}
      today={TODAY}
      dayWidth={30}
      rowLabelWidth={160}
      laneHeight={34}
      label="格納庫ドック割当（入出庫計画）"
    />
  )
}

// --- dock occupancy matrix (ScheduleGrid) ----------------------------------
// Docks × next 7 days — which dock is occupied by which aircraft each day.

const DAY_MS = 86_400_000
function addDays(iso: string, n: number): string {
  const d = new Date(iso + "T00:00")
  return new Date(d.getTime() + n * DAY_MS).toISOString().slice(0, 10)
}
function within(day: string, start: string, end: string): boolean {
  return day >= start && day < end
}

function DockOccupancy() {
  const days = Array.from({ length: 7 }, (_, i) => addDays(TODAY, i))
  const columns = days.map((d) => ({
    id: d,
    label: d.slice(5).replace("-", "/"),
    ariaLabel: d,
  }))
  const rows = DOCKS.map((d) => ({ id: d.id, label: d.label }))

  const cells: ScheduleCell[] = []
  for (const dock of DOCKS) {
    for (const day of days) {
      const plan = DOCK_PLANS.find(
        (p) => p.dockId === dock.id && within(day, p.in, p.out)
      )
      if (!plan) continue
      cells.push({
        rowId: dock.id,
        colId: day,
        tone:
          plan.status === "in-work"
            ? "info"
            : plan.status === "confirmed"
              ? "primary"
              : "muted",
        content: (
          <span className="text-[11px] font-medium leading-tight">
            {plan.reg}
            <br />
            <span className="text-muted-foreground">{plan.check}</span>
          </span>
        ),
        description: `${plan.reg} ${plan.check}`,
      })
    }
  }

  return (
    <ScheduleGrid
      rows={rows}
      columns={columns}
      cells={cells}
      label="ドック占有状況（直近7日）"
      cornerLabel="ドック／日付"
      minColumnWidth={84}
      rowHeaderWidth={140}
    />
  )
}

// --- action queue ----------------------------------------------------------

function ActionPanel() {
  return (
    <ActionQueue
      items={ACTIONS.map((a) => ({
        id: a.id,
        severity: a.severity,
        kind: a.kind,
        title: (
          <span>
            <span className="font-mono font-semibold">{a.reg}</span>{" "}
            {a.title}
          </span>
        ),
        detail: a.detail,
        meta: a.due,
        actions: (
          <Button size="sm" variant="outline">
            対応
          </Button>
        ),
      }))}
      emptyLabel="要対応項目はありません"
    />
  )
}

// --- selected aircraft inspector ------------------------------------------

function AircraftInspector({ aircraft }: { aircraft: Aircraft }) {
  const { consumed, limit, basis, dueDate } = aircraft.due
  const remaining = Math.max(limit - consumed, 0)

  return (
    <InspectorPanel
      title={`${aircraft.reg} — 機体詳細`}
      className="h-auto w-full"
    >
      <InspectorSection title="基本情報">
        <MetadataList
          variant="compact"
          items={[
            { label: "型式", value: aircraft.type },
            { label: "製造番号(MSN)", value: aircraft.msn },
            { label: "配置基地", value: aircraft.base },
            {
              label: "状態",
              value: (
                <Badge variant={STATUS_VARIANT[aircraft.status]}>
                  {STATUS_LABEL[aircraft.status]}
                </Badge>
              ),
            },
            { label: "累積FH", value: `${nf.format(aircraft.fh)} FH` },
            { label: "累積FC", value: `${nf.format(aircraft.fc)} FC` },
          ]}
        />
      </InspectorSection>

      <InspectorSection title={`次回整備：${aircraft.nextCheck}（限度 ${nf.format(limit)}${basis}）`}>
        <InspectorField label={`整備周期 残り（期限 ${dueDate}）`}>
          <Meter
            value={consumed}
            max={limit}
            tone={dueTone(consumed, limit)}
            unit={basis}
            label={`${aircraft.reg} ${aircraft.nextCheck} 周期消費`}
            formatValue={() => `消費 ${nf.format(consumed)} / 限度 ${nf.format(limit)}${basis}（残 ${nf.format(remaining)}${basis}）`}
          />
        </InspectorField>
        <InspectorField label="保留 MEL">
          <span className="text-sm tabular-nums">
            {aircraft.melOpen > 0 ? `${aircraft.melOpen} 件 保留中` : "なし"}
          </span>
        </InspectorField>
      </InspectorSection>

      <InspectorSection title="整備履歴（直近）">
        <Timeline>
          <TimelineItem variant="success">
            <TimelineTime>2026-06-12</TimelineTime>
            <TimelineTitle>A整備（ライン）完了</TimelineTitle>
            <TimelineDescription>HND・WO-7702・適合</TimelineDescription>
          </TimelineItem>
          <TimelineItem variant="info">
            <TimelineTime>2026-03-04</TimelineTime>
            <TimelineTitle>SB施工（ATA34 航法）</TimelineTitle>
            <TimelineDescription>確認主任者 山本</TimelineDescription>
          </TimelineItem>
          <TimelineItem variant="muted" connector={false}>
            <TimelineTime>2025-11-20</TimelineTime>
            <TimelineTitle>C整備 完了</TimelineTitle>
            <TimelineDescription>H1-B・10日間</TimelineDescription>
          </TimelineItem>
        </Timeline>
      </InspectorSection>
    </InspectorPanel>
  )
}

// --- maintenance record sign-off ------------------------------------------

function RecordSignOff() {
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  })

  return (
    <SignedRecord
      value={record}
      onChange={setRecord}
      signerId={RECORD.inspector}
      labels={{
        draft: "下書き",
        signed: "確認済（ロック）",
        sign: "整備確認サインオフ",
        locked: "この記録は確定済みです。追記のみ可能です。",
        addendaTitle: "追記履歴",
        addendum: "追記",
        addendumSubmit: "追記を保存",
      }}
    >
      {({ readOnly }) => (
        <div className="space-y-4">
          <div className="flex flex-wrap items-center gap-2">
            <span className="font-mono text-lg font-semibold">{RECORD.reg}</span>
            <Badge variant="info">{RECORD.check}</Badge>
            <span className="text-sm text-muted-foreground">{RECORD.workOrder}</span>
          </div>
          <MetadataList
            variant="compact"
            layout="horizontal"
            items={[
              { label: "ドック", value: RECORD.dock },
              { label: "整備士", value: RECORD.mechanic },
              { label: "開始", value: RECORD.startedAt.replace("T", " ") },
              { label: "完了", value: RECORD.finishedAt.replace("T", " ") },
              { label: "確認主任者", value: RECORD.inspector },
            ]}
          />
          <div>
            <h4 className="mb-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
              作業実績
            </h4>
            <ul className="divide-y divide-border rounded-md border border-border">
              {RECORD.tasks.map((t) => (
                <li
                  key={t.ata}
                  className="flex items-center justify-between gap-3 px-3 py-2 text-sm"
                >
                  <span className="flex min-w-0 items-center gap-2">
                    <span className="shrink-0 font-mono text-xs text-muted-foreground">
                      {t.ata}
                    </span>
                    <span className="truncate">{t.task}</span>
                  </span>
                  <Badge variant="success">{t.result}</Badge>
                </li>
              ))}
            </ul>
          </div>
          {!readOnly && (
            <p className="text-xs text-muted-foreground">
              内容を確認のうえ「整備確認サインオフ」で確定してください。確定後は編集不可（追記のみ）になります。
            </p>
          )}
        </div>
      )}
    </SignedRecord>
  )
}

// --- KPI strip -------------------------------------------------------------

function KpiStrip() {
  const inService = FLEET.filter((a) => a.status === "in-service").length
  const inHangar = FLEET.filter((a) => a.status === "in-hangar").length
  const attention = FLEET.filter((a) => a.status === "attention").length
  const critical = ACTIONS.filter((a) => a.severity === "critical").length

  return (
    <StatGroup
      cols={{ base: 2, md: 5 }}
      items={[
        { label: "保有機材", value: `${FLEET.length} 機` },
        { label: "運用中", value: `${inService} 機`, hint: "in-service" },
        { label: "整備中(入庫)", value: `${inHangar} 機`, hint: "in-hangar" },
        {
          label: "要注意",
          value: `${attention} 機`,
          trend: attention > 0 ? "up" : "flat",
          tone: "negative",
          hint: "限度接近 / 超過",
        },
        {
          label: "重大アラート",
          value: `${critical} 件`,
          trend: critical > 0 ? "up" : "flat",
          tone: "negative",
          hint: "即対応",
        },
      ]}
    />
  )
}

// --- page ------------------------------------------------------------------

export default function AircraftMaintenance() {
  const [selected, setSelected] = React.useState<Aircraft>(FLEET[0])

  return (
    <main className="mx-auto w-full max-w-[1600px] px-4 py-6 sm:px-6 lg:px-8">
      <PageHeader
