                <CardDescription>
                  格納庫ドック × 時間軸の入出庫計画。作業中=青／確定=群青／計画=灰。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Tabs defaultValue="gantt">
                  <TabsList>
                    <TabsTrigger value="gantt">ガント（期間）</TabsTrigger>
                    <TabsTrigger value="grid">占有マトリクス（7日）</TabsTrigger>
                  </TabsList>
                  <TabsContent value="gantt">
                    <DockPlanGantt />
                  </TabsContent>
                  <TabsContent value="grid">
                    <DockOccupancy />
                  </TabsContent>
                </Tabs>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle as="h2">整備記録 / 確認サインオフ</CardTitle>
                <CardDescription>
                  C整備 {RECORD.workOrder}（{RECORD.reg}）の作業実績。サインオフで確定・ロック（以降は追記のみ）。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <RecordSignOff />
              </CardContent>
            </Card>
          </div>

          {/* side column */}
          <div className="min-w-0 space-y-6">
            <Card>
              <CardHeader>
                <CardTitle as="h2">要対応キュー</CardTitle>
                <CardDescription>重大度順。AD/SB・MEL・限度接近・LLP。</CardDescription>
              </CardHeader>
              <CardContent>
                <ActionPanel />
              </CardContent>
            </Card>

            <AircraftInspector aircraft={selected} />
          </div>
        </div>
      </div>
    </main>
  )
}

// Realistic aircraft-maintenance (MRO) domain data for the operator console.
// Fictional carrier "群青エアラインズ (Gunjo Airlines)"; registrations/types are
// plausible Japanese-fleet shapes (JAxxxx). Not real ops data.

export type FleetStatus = "in-service" | "in-hangar" | "attention"
export type CheckType = "ライン" | "A整備" | "C整備" | "重整備(D)"

export interface Aircraft {
  /** 機番(レジ) */
  reg: string
  /** 型式 */
  type: string
  /** 製造番号(MSN) */
  msn: string
  /** 配置基地 */
  base: string
  status: FleetStatus
  /** 現在の累積飛行時間 (FH) */
  fh: number
  /** 現在の累積飛行サイクル (FC) */
  fc: number
  /** 次回整備種別 */
  nextCheck: CheckType
  /** 次回整備の支配的限度: 残りと限度をFHまたは日で持つ */
  due: {
    /** 限度の種類 */
    basis: "FH" | "FC" | "日"
    /** 消費済み（限度に対して） */
    consumed: number
    /** 限度 */
    limit: number
    /** 期限日 (YYYY-MM-DD) */
    dueDate: string
  }
  /** 保留中の MEL 件数 */
  melOpen: number
  /** 現在ドックにいる場合のドックID */
  dockId?: string
}

